var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"풍속 안정. 시야 청명...... 기후 양호.","JPN":"風速安定。視野良し……気候良好。","ENG":"Winds, stable. Visibility, clear. Weather, favorable.","TWN":"風速穩定、視野清晰……天氣良好。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"저격 포인트 확보 완료했습니다, 사장님.","JPN":"狙撃ポイントの確保を完了しました、社長。","ENG":"I've secured the sniping site, Boss.","TWN":"已確保狙擊點，老闆。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하아...... 하아......","JPN":"はあ……はあ……","ENG":"*Huff... Huff...*","TWN":"哈啊……哈啊……"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"명색이 맨션의 메이드장이었던 자가 눈 뜨고 못 봐 줄 만큼 어설퍼졌군요.","JPN":"かつてはマンションのメイド長ともあろう者が、今では見ていられないほど動きが鈍くなりましたね。","ENG":"You've grown embarrassingly sloppy for someone who was once hailed as the Chief Maid of the Mansion.","TWN":"好歹妳以前是曼森的女僕長，沒想到現在的實力竟如此不堪。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"겁쟁이처럼 몸을 사리는 꼬락서니라니. 쫓아온 제가 다 한숨이 나올 지경이에요.","JPN":"臆病者みたいに受け身ばっかりで。あなたを追いかけていた自分が恥ずかしくなります。","ENG":"To see you running like a coward even has me sighing with contemptuous pity.","TWN":"畏首畏尾的膽小鬼，根本就不值得我出馬。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"으윽! 이거 풀어 주시지 말임다!","JPN":"うっ！　放してほしいっす！","ENG":"Ugh! Lemme go!","TWN":"呃！快給我解開！"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"얌전히 좀 있어, 꼬맹아! 너 그러다 혼난다?!","JPN":"大人しくして、このチビ！　痛い目に遭いたいの！？","ENG":"Stay still, kid! Or I'll spank you!","TWN":"安靜點，小鬼！妳是不是討罵？！"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"모, 모네......","JPN":"モ、モネ……","ENG":"M-Mone...","TWN":"莫、莫妮……"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"제, 제성함다, 메이드장님......","JPN":"ご、ごめんなさいっす。メイド長……","ENG":"S-sorry, ma'am...","TWN":"對、對不起，女僕長大人……"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"이 꼬맹이는 카운터인데, 어떻게 할 거야?","JPN":"このチビはカウンターなんだけど、どうする？","ENG":"The kid is a Counter. What should we do with her?","TWN":"那小鬼好像是制裁者，怎麼辦？"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"벌써 배신자에게 물이 든 것 같지만, 그 정도야 교육으로 해결할 수 있는 문제죠.","JPN":"すでに裏切り者に洗脳されているようですが、それくらい教育で何とか解決できると思います。","ENG":"The traitor seems to have gotten in her head already, but it's nothing that a little education can't fix.","TWN":"貌似她已經受到了叛徒的影響，不過教育一下就可以了。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마스터께서도 싫어하시진 않겠어요. 배신자는 이 자리에서 폐기하고 꼬마는 데려갑니다.","JPN":"マスターも同意するでしょう。裏切り者はこの場で廃棄して子どもは連れて帰ります。","ENG":"The Master will be pleased as well. We'll dispose of the traitor here and take the kid.","TWN":"頭目應該也挺喜歡的，叛徒就地處決，小孩子我們帶走。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"나, 납치범은 싫슴다! 안 따라갈 검다!","JPN":"ひ、人さらいはイヤっす！　行きたくないっす！","ENG":"I-I don't wanna be kidnapped! I won't let you take me!","TWN":"我、我討厭綁匪！我才不要跟你們走！"},"stage":{"bg":"DOCK_DAY","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"메이드 주제에 목청이 크군요.","JPN":"メイドとしては声が大きすぎますね。","ENG":"You're too loud to be a maid.","TWN":"區區一個女僕，嗓門怎麼這麼大。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"기다리고 계세요. 배신자를 정리한 다음에 메이드가 지켜야 할 자세를 확실하게 가르쳐 드리죠.","JPN":"楽しみにしてくださいね。裏切り者を処分した後、メイドのたしなみや心構えについてじっくりお教えします。","ENG":"Stay put. We'll teach you how to be a proper maid once we've put down the traitor.","TWN":"等我處決了叛徒之後，我再教妳女僕應該守的規矩。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"끝입니다. 배신자.","JPN":"ここでお終いです、裏切り者。","ENG":"It ends here, traitor.","TWN":"妳的好日子該結束了，叛徒。"},"stage":{"bg":"DOCK_DAY","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};